const rootApi = "https://sumari.weathervietnam.vn/api/v3/backend";
const authenApi = "http://192.168.1.71:3030/api/v3/backend";
const stationApi = "http://192.168.1.71:3030/api/v3/backend"; //http://10.151.2.7:3038/
const addressApi = "https://sumari1.weathervietnam.vn/api/v3/area";

// ── Token key giống hệ thống cũ ───────────────────────────────────────────────
const TOKEN_KEY = 'aiJwt';

// ── Headers — giống hệt pattern cũ ───────────────────────────────────────────
export const HEADERS = {
  DEFAULT_HEADER: { 'Content-Type': 'application/json; charset=UTF-8' },
  JWT_HEADER: () => ({
    'Content-Type': 'application/json; charset=UTF-8',
    Authorization: localStorage.getItem(TOKEN_KEY),
    accept: 'application/json',
  }),
};

// ── Auth helpers ──────────────────────────────────────────────────────────────
export const auth = {
  getToken: () => localStorage.getItem(TOKEN_KEY),

  // Lưu dạng "Bearer xxx" giống hệ thống cũ dùng aiJwt
  setToken: (token) => localStorage.setItem(TOKEN_KEY, `Bearer ${token}`),
  removeToken: () => localStorage.removeItem(TOKEN_KEY),
  isLoggedIn: () => !!localStorage.getItem(TOKEN_KEY),

  login: async (user_name, user_pass) => {
    const res = await fetch(`${authenApi}/users/login`, {
        method: 'POST',
        headers: HEADERS.DEFAULT_HEADER,
        body: JSON.stringify({ user_name, user_pass }),
      });
    
      // Đọc text trước, rồi mới parse JSON — tránh crash khi server trả plain text
      const text = await res.text();
      let data = {};
      try { data = JSON.parse(text); } catch (_) {}
    
      if (!res.ok) {
        throw new Error(data.message || data.detail || `Sai tài khoản hoặc mật khẩu (${res.status})`);
      }
    
      const token =
        data.access_token ||
        data.token ||
        data.data?.access_token ||
        data.data?.token;
      if (!token) throw new Error('Không nhận được token từ server');
      auth.setToken(token);
      return token;
  },

  logout: () => {
    auth.removeToken();
    window.location.reload();
  },
};

// ── API endpoints — cùng pattern với API.js cũ ────────────────────────────────
export const API = {
  AUTH: {
    login: () => ({
      endPoint: `${authenApi}/login`,
      method: 'POST',
      headers: HEADERS.DEFAULT_HEADER,
    }),
  },

  TRUNGBO: {
    getAll: () => ({
      endPoint: `${stationApi}/trungbo-aws-config/`,
      method: 'GET',
      headers: HEADERS.JWT_HEADER(),
    }),
    getById: (id) => ({
      endPoint: `${stationApi}/trungbo-aws-config/${id}`,
      method: 'GET',
      headers: HEADERS.JWT_HEADER(),
    }),
    create: () => ({
      endPoint: `${stationApi}/trungbo-aws-config/`,
      method: 'POST',
      headers: HEADERS.JWT_HEADER(),
    }),
    update: (id) => ({
      endPoint: `${stationApi}/trungbo-aws-config/${id}`,
      method: 'PUT',
      headers: HEADERS.JWT_HEADER(),
    }),
    delete: (id) => ({
      endPoint: `${stationApi}/trungbo-aws-config/${id}`,
      method: 'DELETE',
      headers: HEADERS.JWT_HEADER(),
    }),
  },
};

// ── Hàm gọi API chung (dùng thay fetch trực tiếp) ────────────────────────────
export async function callApi({ endPoint, method, headers }, body = null) {
  const options = { method, headers };
  if (body) options.body = JSON.stringify(body);
  const res = await fetch(endPoint, options);
  if (res.status === 401) {
    auth.removeToken();
    window.location.reload();
    return;
  }
  if (!res.ok) throw new Error(`Lỗi ${res.status}: ${res.statusText}`);
  return res.json();
}
